#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 105;
const int M = 10000*N;
LL n,a[N],sum,dp[2][M];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),sum=0;
    for(int i=1;i<=n;i++)
        a[i]=read(),sum+=a[i];
    if(n%2==1||sum%2==1||n<4){
        cout<<"No\n";return 0;
    }
    memset(dp,0,sizeof(dp));
    dp[0][0]=1;
    for(int i=1;i<=n;i++)
        for(int j=sum;j>=a[i];j--)
            dp[1][j]+=dp[0][j-a[i]],
            dp[0][j]+=dp[1][j-a[i]];
    if(dp[0][sum/2]/2>=2)cout<<"Yes\n";
    else cout<<"No\n";
    return 0;
}
